// org.apache.commons.cli2.application.CpTest::testHelp
    public void testHelp() throws IOException {
        final StringWriter out = new StringWriter();
        final HelpFormatter helpFormatter = new HelpFormatter();
        helpFormatter.setGroup(options);
        helpFormatter.setPrintWriter(new PrintWriter(out));
        helpFormatter.print();

        final BufferedReader in =
            new BufferedReader(new StringReader(out.toString()));
        assertEquals(
            "Usage:                                                                          ",
            in.readLine());
        assertEquals(
            " [-a -b -d -f -i -l -p -P -r --sparse <WHEN> -R -s -S <SUFFIX> -u -v -V <WORD>  ",
            in.readLine());
        assertEquals(
            "-x --help --version] <SOURCE1> [<SOURCE2> ...] <DEST>                           ",
            in.readLine());
        assertEquals(
            "OPTIONS                                                                         ",
            in.readLine());
        assertEquals(
            "  -a (--archive)                same as -dpR                                    ",
            in.readLine());
        assertEquals(
            "  -b (--backup)                 make backup before removal                      ",
            in.readLine());
        assertEquals(
            "  -d (--no-dereference)         preserve links                                  ",
            in.readLine());
        assertEquals(
            "  -f (--force)                  remove existing destinations, never prompt      ",
            in.readLine());
        assertEquals(
            "  -i (--interactive)            prompt before overwrite                         ",
            in.readLine());
        assertEquals(
            "  -l (--link)                   link files instead of copying                   ",
            in.readLine());
        assertEquals(
            "  -p (--preserve)               preserve file attributes if possible            ",
            in.readLine());
        assertEquals(
            "  -P (--parents)                append source path to DIRECTORY                 ",
            in.readLine());
        assertEquals(
            "  -r                            copy recursively, non-directories as files      ",
            in.readLine());
        assertEquals(
            "  --sparse WHEN                 control creation of sparse files                ",
